import "../styles/Fa";

export default function FAQs() {
  return (
    <section className="faqs-section">
      <h3>Frequently Asked Questions</h3>
      <div className="faq">
        <strong>Q: What is your turnaround time?</strong>
        <p>A: Typically 2–4 weeks, depending on the project scope.</p>
      </div>
    </section>
  );
}
